javascript:(async()=>{const DEBUG=true;const TARGET_VERSION="2026.05.05-PRINT-COOLDOWN-FIX";const URL="https://raw.githubusercontent.com/AnonymousHer/DMR_PRO_CODE/main/dmr-pro.min.js";const log=(...a)=>{if(DEBUG)console.log("[DMR LOADER]",...a)};try{Object.keys(localStorage).filter(k=>k.startsWith("DMR_")).forEach(k=>{log("silindi:",k);localStorage.removeItem(k)});let u=URL+"?v="+Date.now();log("yükleniyor:",u);let r=await fetch(u,{cache:"no-store"});if(!r.ok)throw new Error("HTTP "+r.status);let t=await r.text();window.DMR_LOADER_VERSION=TARGET_VERSION;log("version:",TARGET_VERSION,"boyut:",t.length);eval(t)}catch(e){console.error("[DMR LOADER ERROR]",e);alert("DMR yüklenemedi: "+e.message)}})();